import{_ as n,C as o,o as t,c as s,a4 as r,b as d,w as i,a as c,E as h,a5 as p}from"./chunks/framework.lC8lx-25.js";const w=JSON.parse('{"title":"Architecture","description":"How the JSVision engine fits together — its subsystems, data flow, and the decisions behind them.","frontmatter":{"title":"Architecture","description":"How the JSVision engine fits together — its subsystems, data flow, and the decisions behind them."},"headers":[],"relativePath":"reference/architecture/index.md","filePath":"reference/architecture/index.md"}'),l={name:"reference/architecture/index.md"};function u(g,e,m,f,y,b){const a=o("Mermaid");return t(),s("div",null,[e[1]||(e[1]=r('<h1 id="jsvision-—-technical-architecture" tabindex="-1">jsvision — Technical Architecture <a class="header-anchor" href="#jsvision-—-technical-architecture" aria-label="Permalink to &quot;jsvision — Technical Architecture&quot;">​</a></h1><blockquote><p><strong>Project</strong>: jsvision <strong>Type</strong>: Library / SDK (terminal UI foundation) <strong>Tech Stack</strong>: TypeScript (ESM-only, NodeNext, strict), Node ≥ 18, zero runtime dependencies <strong>Last Updated</strong>: 2026-06-28</p></blockquote><hr><h2 id="system-purpose" tabindex="-1">System Purpose <a class="header-anchor" href="#system-purpose" aria-label="Permalink to &quot;System Purpose&quot;">​</a></h2><p><code>@jsvision/core</code> is the foundation package of an SDK for building Turbo Vision-style terminal (TUI) applications in TypeScript. It provides the cross-cutting machinery a terminal app needs before any widget exists: detecting what the terminal can do, decoding raw input bytes into events, composing and diffing a screen into minimal ANSI, encoding colour for the detected depth, owning the terminal lifecycle (raw mode, alt-screen, guaranteed restore), and a safety layer that keeps untrusted bytes and screen state from corrupting the session.</p><p>It is written for application and widget authors who want a correct, capability-aware rendering and input core without re-deriving terminal arcana. Everything is a pure function or a thin seam over a Node built-in, so it is testable without a real TTY and ships with <strong>zero runtime dependencies</strong>.</p><p>This package is the <strong>foundation</strong> only — widgets, layout, and an application runloop are built on top of it, not inside it.</p><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2>',8)),(t(),d(p,null,{default:i(()=>[h(a,{id:"mermaid-24",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20App%5BApplication%20%2F%20Widgets%5D%20--%3E%20Index%5BPublic%20entry%3A%20src%2Fengine%2Findex.ts%5D%0A%20%20%20%20Index%20--%3E%20Capability%5BCapability%20detection%20RD-02%5D%0A%20%20%20%20Index%20--%3E%20Input%5BInput%20decoder%20RD-06%5D%0A%20%20%20%20Index%20--%3E%20Render%5BRendering%20engine%20RD-04%5D%0A%20%20%20%20Index%20--%3E%20Color%5BColor%20%26%20styling%20RD-05%5D%0A%20%20%20%20Index%20--%3E%20Host%5BHost%20%26%20lifecycle%20RD-07%5D%0A%20%20%20%20Index%20--%3E%20Safety%5BSafety%20RD-08%5D%0A%20%20%20%20Render%20--%3E%20Color%0A%20%20%20%20Host%20--%3E%20Capability%0A%20%20%20%20Host%20--%3E%20Input%0A%20%20%20%20Capability%20--%3E%20Safety%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=r('<h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Module</th><th>Purpose</th><th>Documentation</th></tr></thead><tbody><tr><td>Capability detection</td><td><code>src/engine/capability/</code></td><td>Detect terminal capabilities; auto-configure</td><td><a href="/jsvision/pr-preview/pr-80/reference/architecture/api-design.html">API Design</a></td></tr><tr><td>Input decoder</td><td><code>src/engine/input/</code></td><td>Pure byte→event decoding (keys, mouse, paste)</td><td><a href="/jsvision/pr-preview/pr-80/reference/architecture/api-design.html">API Design</a></td></tr><tr><td>Rendering engine</td><td><code>src/engine/render/</code></td><td>Width-correct buffer + pure damage-diff serialize</td><td><a href="/jsvision/pr-preview/pr-80/reference/architecture/api-design.html">API Design</a></td></tr><tr><td>Color &amp; styling</td><td><code>src/engine/color/</code></td><td>Depth-aware SGR encoding (truecolor→256→16→mono)</td><td><a href="/jsvision/pr-preview/pr-80/reference/architecture/api-design.html">API Design</a></td></tr><tr><td>Host &amp; lifecycle</td><td><code>src/engine/host/</code></td><td>Raw mode, alt-screen, signals, guaranteed restore</td><td><a href="/jsvision/pr-preview/pr-80/reference/architecture/system-overview.html">System Overview</a></td></tr><tr><td>Safety</td><td><code>src/engine/safety/</code></td><td>Essentials gate, sanitize boundary, typed errors</td><td><a href="/jsvision/pr-preview/pr-80/reference/architecture/security.html">Security</a></td></tr></tbody></table><h2 id="technology-decisions" tabindex="-1">Technology Decisions <a class="header-anchor" href="#technology-decisions" aria-label="Permalink to &quot;Technology Decisions&quot;">​</a></h2><p>See <a href="/jsvision/pr-preview/pr-80/reference/decisions/">Architecture Decision Records</a> for the rationale behind the major design choices (ESM-only zero-dep, capability auto-config, pure core behind injectable seams, no node-pty, the canonical sanitize boundary, and the informational performance bench).</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>New to the project? Start with the <a href="/jsvision/pr-preview/pr-80/reference/guides/getting-started.html">Getting Started Guide</a>, then read the <a href="/jsvision/pr-preview/pr-80/reference/architecture/system-overview.html">System Overview</a>.</p>',6))])}const S=n(l,[["render",u]]);export{w as __pageData,S as default};
